pre_capture_js:
() => {
  const btn = document.querySelector("gs-nav-button[data-qa-id='rosteringScenarios'] a.nav-button.nav-button--active")
    || document.querySelector("gs-nav-button[data-qa-id='rosteringScenarios'] a.nav-button");
  const tips = Array.from(document.querySelectorAll('gs-tooltip'));
  if (!btn || !tips.length) return;

  const visibleTips = tips.filter(t => {
    const r = t.getBoundingClientRect();
    return r.width > 0 && r.height > 0;
  });
  const candidates = visibleTips.length ? visibleTips : tips;

  const br = btn.getBoundingClientRect();
  const bx = br.left + (br.width / 2);
  const by = br.bottom;

  let tip = candidates[0];
  let best = Number.POSITIVE_INFINITY;
  for (const t of candidates) {
    const tr = t.getBoundingClientRect();
    const tx = tr.left + (tr.width / 2);
    const ty = tr.top;
    const score = Math.abs(tx - bx) + Math.abs(ty - by);
    if (score < best) {
      best = score;
      tip = t;
    }
  }

  tips.forEach(t => t.removeAttribute('data-capture-anchor'));
  tip.setAttribute('data-capture-anchor', 'rostering-tooltip');

  const tipWrap = tip.closest('.cdk-overlay-connected-position-bounding-box');
  if (tipWrap) {
    tipWrap.style.left = '0px';
    tipWrap.style.top = '0px';
    tipWrap.style.width = '100vw';
    tipWrap.style.height = '100vh';
    tipWrap.style.position = 'fixed';
    tipWrap.style.display = 'block';
    tipWrap.style.transform = 'none';
  }

  const pane = tip.closest('.cdk-overlay-pane');
  if (pane) {
    pane.style.position = 'fixed';
    pane.style.transform = 'none';
  }

  tip.style.position = 'fixed';
  tip.style.margin = '0';
  tip.style.transform = 'translateX(-50%)';
  tip.style.zIndex = '10001';
  tip.style.left = `${Math.round(br.left + br.width / 2)}px`;
  tip.style.top = `${Math.round(br.bottom + 8)}px`;
}
